// Power Manager v6.0 Configuration
// All settings centralized here

const config = {
    // === UNIT CONVERSIONS ===
    // Multiply raw sensor values by these factors
    units: {
        p1: 1000,      // P1 meter: kW → W
        pv: 1,         // SolarEdge: already in W
        boiler: 1,
        poolHeat: 1,
        ev: 1,
        acLiving: 1,
        acBureau: 1
    },

    // === GRID LIMITS ===
    maxImport: {
        peak: 2500,
        offPeak: 5000,
        superOffPeak: 8000
    },

    // === TIMING (seconds) ===
    hysteresis: 300,        // Power buffer before switching
    minOnTime: 300,         // Minimum on-time before allowing off
    minOffTime: 180,        // Minimum off-time before allowing on
    evAmpChangeThreshold: 2, // Min amp change to avoid flapping

    // === EV CHARGER ===
    ev: {
        minAmps: 6,
        maxAmps: 16,
        wattsPerAmp: 692,
        // State codes from ABB Terra AC
        states: {
            NO_CAR: 128,
            READY: 129,
            FULL: 130,
            CHARGING: 132
        }
    },

    // === BOILER ===
    boiler: {
        power: 2500,
        idleThreshold: 50,      // Below this = fully heated
        deadlineWinter: 6.5,    // 06:30 - must be hot by this time
        deadlineSummer: 8.0     // 08:00
    },

    // === POOL HEAT PUMP ===
    pool: {
        idlePower: 100,
        activePower: 2000
    },

    // === HEATERS ===
    heaters: {
        right: { power: 2500 },
        table: { power: 4100 }
    },

    // === AC UNITS ===
    ac: {
        living:   { power: 1500, winterSetpoint: 21 },
        mancave:  { power: 1000, winterSetpoint: 17 },
        office:   { power: 1000, winterSetpoint: 22 },
        bedroom:  { power: 1000, winterSetpoint: 22 }
    },

    // === TEMPERATURE ===
    summerCoolThreshold: 25,
    summerTargetTemp: 22,

    // === ENTITIES ===
    // Centralized entity registry - change here, not in handlers
    entities: {
        p1: 'sensor.electricity_meter_power_consumption',
        pv: 'sensor.solaredge_i1_ac_power',
        ev: {
            switch: 'switch.abb_terra_ac_charging',
            power: 'sensor.abb_terra_ac_active_power',
            limit: 'number.abb_terra_ac_current_limit',
            state: 'sensor.abb_terra_ac_charging_state'
        },
        boiler: {
            switch: 'switch.storage_boiler',
            power: 'sensor.storage_boiler_power',
            force: 'input_boolean.force_heat_boiler'
        },
        pool: {
            climate: 'climate.98d8639f920c',
            power: 'sensor.pool_heating_current_consumption',
            season: 'input_boolean.pool_season'
        },
        heaters: {
            right: 'switch.livingroom_right_heater',
            table: 'switch.livingroom_table_heater_state'
        },
        ac: {
            living: 'climate.living',
            mancave: 'climate.mancave',
            office: 'climate.bureau',
            bedroom: 'climate.slaapkamer'
        },
        acPower: {
            living: 'sensor.living_current_power',
            office: 'sensor.bureau_current_power'
        },
        temp: {
            living: 'sensor.livingroom_temperature_temperature',
            bedroom: 'sensor.bedroom_temperature_temperature',
            mancave: 'sensor.mancave_inside_temperature'
        },
        overrides: {
            acLiving: 'input_select.pm_override_ac_living',
            acBedroom: 'input_select.pm_override_ac_slaapkamer',
            acOffice: 'input_select.pm_override_ac_bureau',
            acMancave: 'input_select.pm_override_ac_mancave',
            pool: 'input_select.pm_override_pool',
            boiler: 'input_select.pm_override_boiler',
            ev: 'input_select.pm_override_ev'
        },
        status: {
            status: 'input_text.power_manager_status',
            plan: 'input_text.power_manager_plan',
            actions: 'input_text.power_manager_actions'
        }
    },

    // === OPTIONS ===
    enableNotifications: true,
    locale: 'en-GB',
    debug: false
};

// Store in flow context
flow.set('config', config);

// Initialize action log if not exists
if (!flow.get('actionLog')) {
    flow.set('actionLog', []);
}

// Initialize last run timestamp for throttling
if (!flow.get('lastRun')) {
    flow.set('lastRun', 0);
}

node.status({ fill: 'green', shape: 'dot', text: 'Config v6.0' });
return null;

// Initialize device state tracking
flow.set('deviceState', {
    ev: { on: false, lastChange: 0, amps: 0 },
    boiler: { on: false, lastChange: 0 },
    pool: { on: false, lastChange: 0 },
    heaterRight: { on: false, lastChange: 0 },
    heaterTable: { on: false, lastChange: 0 },
    acLiving: { on: false, lastChange: 0 },
    acMancave: { on: false, lastChange: 0 },
    acOffice: { on: false, lastChange: 0 },
    acBedroom: { on: false, lastChange: 0 }
});

// Clear action log
flow.set('actionLog', []);

// Initialize mutex for trigger gating
flow.set('isProcessing', false);

node.status({ fill: 'green', shape: 'dot', text: 'Initialized' });
return null;

// Prevent concurrent executions
const isProcessing = flow.get('isProcessing') || false;
const lastRun = flow.get('lastRun') || 0;
const now = Date.now();
const minInterval = 3000; // 3 seconds minimum between runs

if (isProcessing) {
    node.status({ fill: 'yellow', shape: 'ring', text: 'Skipped (processing)' });
    return null;
}

if (now - lastRun < minInterval) {
    node.status({ fill: 'yellow', shape: 'ring', text: 'Skipped (throttle)' });
    return null;
}

flow.set('isProcessing', true);
flow.set('lastRun', now);

node.status({ fill: 'green', shape: 'dot', text: 'Running' });
return msg;

// Validate and sanitize all inputs before processing
const config = flow.get('config') || {};

// Helper to safely parse numeric values
function safeNum(val, fallback = 0) {
    if (val === null || val === undefined) return fallback;
    if (val === 'unavailable' || val === 'unknown') return fallback;
    const num = parseFloat(val);
    return isNaN(num) ? fallback : num;
}

// Helper to safely parse string values
function safeStr(val, fallback = '') {
    if (val === null || val === undefined) return fallback;
    if (val === 'unavailable' || val === 'unknown') return fallback;
    return String(val);
}

// Validate and normalize all values
msg.validated = {
    // Power readings
    p1Power: safeNum(msg.p1_power, 0),
    pvPower: safeNum(msg.pv_power, 0),

    // Device states (switches)
    boilerSwitch: safeStr(msg.boiler_switch, 'unknown'),
    boilerPower: safeNum(msg.boiler_power, 0),
    boilerForce: safeStr(msg.boiler_force, 'off'),

    poolSeason: safeStr(msg.pool_season, 'off'),
    poolPower: safeNum(msg.pool_power, 0),
    poolClimate: safeStr(msg.pool_climate, 'off'),

    evState: safeNum(msg.ev_state, 128),  // 128 = no car
    evSwitch: safeStr(msg.ev_switch, 'off'),
    evPower: safeNum(msg.ev_power, 0),
    evLimit: safeNum(msg.ev_limit, 6),

    heaterRightSwitch: safeStr(msg.heater_right_switch, 'off'),
    heaterTableSwitch: safeStr(msg.heater_table_switch, 'off'),

    // AC states
    acLivingState: safeStr(msg.ac_living_state, 'off'),
    acMancaveState: safeStr(msg.ac_mancave_state, 'off'),
    acOfficeState: safeStr(msg.ac_office_state, 'off'),
    acBedroomState: safeStr(msg.ac_bedroom_state, 'off'),

    // Power readings
    acLivingPower: safeNum(msg.ac_living_power, 0),
    acOfficePower: safeNum(msg.ac_office_power, 0),

    // Temperatures
    tempLiving: safeNum(msg.temp_living, 20),
    tempBedroom: safeNum(msg.temp_bedroom, 20),
    tempMancave: safeNum(msg.temp_mancave, 20),

    // Overrides
    ovrAcLiving: safeStr(msg.ovr_ac_living, ''),
    ovrAcBedroom: safeStr(msg.ovr_ac_bedroom, ''),
    ovrAcOffice: safeStr(msg.ovr_ac_office, ''),
    ovrAcMancave: safeStr(msg.ovr_ac_mancave, ''),
    ovrPool: safeStr(msg.ovr_pool, ''),
    ovrBoiler: safeStr(msg.ovr_boiler, ''),
    ovrEv: safeStr(msg.ovr_ev, '')
};

// Check for critical unavailable entities
const warnings = [];
if (msg.p1_power === 'unavailable') warnings.push('P1 meter unavailable');
if (msg.pv_power === 'unavailable') warnings.push('PV sensor unavailable');

if (warnings.length > 0) {
    node.warn('Input validation warnings: ' + warnings.join(', '));
}

node.status({ fill: 'green', shape: 'dot', text: 'Validated' });
return msg;

// Power Manager v6.0 - English version with improved error handling
const config = flow.get('config') || {};
let deviceState = flow.get('deviceState') || {};
let actionLog = flow.get('actionLog') || [];
const now = Date.now();
const units = config.units || {};
const v = msg.validated || {};

// === CONSTANTS ===
const EV_STATES = config.ev?.states || { NO_CAR: 128, READY: 129, FULL: 130, CHARGING: 132 };

// === HELPER FUNCTIONS ===
function fmtW(w) {
    return Math.abs(w) >= 1000 ? (w/1000).toFixed(1) + 'kW' : Math.round(w) + 'W';
}

function fmtTime(h) {
    return String(Math.floor(h)).padStart(2,'0') + ':' + String(Math.round((h % 1) * 60)).padStart(2,'0');
}

function getTariffInfo(d) {
    const time = d.getHours() + d.getMinutes() / 60;
    const isWeekend = d.getDay() === 0 || d.getDay() === 6;

    if (isWeekend) {
        if (time >= 1 && time < 7) return { tariff: 'super-off-peak', max: config.maxImport?.superOffPeak || 8000, end: 7, next: 'off-peak', nextTime: '07:00' };
        if (time >= 7 && time < 11) return { tariff: 'off-peak', max: config.maxImport?.offPeak || 5000, end: 11, next: 'super-off-peak', nextTime: '11:00' };
        if (time >= 11 && time < 17) return { tariff: 'super-off-peak', max: config.maxImport?.superOffPeak || 8000, end: 17, next: 'off-peak', nextTime: '17:00' };
        return { tariff: 'off-peak', max: config.maxImport?.offPeak || 5000, end: 1, next: 'super-off-peak', nextTime: '01:00' };
    } else {
        if (time >= 1 && time < 7) return { tariff: 'super-off-peak', max: config.maxImport?.superOffPeak || 8000, end: 7, next: 'peak', nextTime: '07:00' };
        if (time >= 7 && time < 11) return { tariff: 'peak', max: config.maxImport?.peak || 2500, end: 11, next: 'off-peak', nextTime: '11:00' };
        if (time >= 11 && time < 17) return { tariff: 'off-peak', max: config.maxImport?.offPeak || 5000, end: 17, next: 'peak', nextTime: '17:00' };
        if (time >= 17 && time < 22) return { tariff: 'peak', max: config.maxImport?.peak || 2500, end: 22, next: 'off-peak', nextTime: '22:00' };
        return { tariff: 'off-peak', max: config.maxImport?.offPeak || 5000, end: 1, next: 'super-off-peak', nextTime: '01:00' };
    }
}

function getNextNonPeak(d) {
    const time = d.getHours() + d.getMinutes() / 60;
    const isWeekend = d.getDay() === 0 || d.getDay() === 6;
    if (isWeekend) return { time: '01:00', tariff: 'super-off-peak', max: 8000 };
    if (time >= 7 && time < 11) return { time: '11:00', tariff: 'off-peak', max: 5000 };
    if (time >= 17 && time < 22) return { time: '22:00', tariff: 'off-peak', max: 5000 };
    if (time >= 22 || time < 1) return { time: '01:00', tariff: 'super-off-peak', max: 8000 };
    return { time: '01:00', tariff: 'super-off-peak', max: 8000 };
}

function canSwitch(device, targetState) {
    const state = deviceState[device];
    if (!state) return true;
    const elapsed = (now - state.lastChange) / 1000;
    const minTime = targetState ? (config.minOffTime || 180) : (config.minOnTime || 300);
    return elapsed >= minTime;
}

function updateState(device, on, extra = {}) {
    if (!deviceState[device]) deviceState[device] = { on: false, lastChange: 0 };
    if (deviceState[device].on !== on) deviceState[device].lastChange = now;
    deviceState[device].on = on;
    Object.assign(deviceState[device], extra);
    flow.set('deviceState', deviceState);
}

function logAction(action) {
    // Throttle logging - max 1 entry per 30 seconds per action type
    const lastActions = flow.get('lastLoggedActions') || {};
    const actionKey = action.substring(0, 20);
    if (lastActions[actionKey] && (now - lastActions[actionKey]) < 30000) {
        return; // Skip duplicate log
    }
    lastActions[actionKey] = now;
    flow.set('lastLoggedActions', lastActions);

    const ts = new Date().toLocaleTimeString(config.locale || 'en-GB', {hour: '2-digit', minute: '2-digit'});
    actionLog.unshift(`${ts} ${action}`);
    if (actionLog.length > 15) actionLog.pop();
    flow.set('actionLog', actionLog);
}

function parseOverride(val) {
    if (!val) return 'auto';
    const v = val.toLowerCase();
    if (v.includes('auto')) return 'auto';
    if (v.includes('koel') || v.includes('cool')) return 'cool';
    if (v.includes('verwarm') || v.includes('heat') || v.includes('aan') || v.includes('on') || v.includes('lad') || v.includes('charg')) return 'heat';
    if (v.includes('uit') || v.includes('off')) return 'off';
    return 'auto';
}

// === MAIN DATA ===
const p1 = v.p1Power * (units.p1 || 1);
const pv = v.pvPower * (units.pv || 1);
const d = new Date();
const tariffInfo = getTariffInfo(d);
const tariff = tariffInfo.tariff;
const maxImport = tariffInfo.max;
const hyst = config.hysteresis || 300;
const nextNonPeak = getNextNonPeak(d);

const isSummer = v.poolSeason === 'on';
const isExporting = p1 < 0;

// Parse overrides
const ovr = {
    acLiving: parseOverride(v.ovrAcLiving),
    acBedroom: parseOverride(v.ovrAcBedroom),
    acOffice: parseOverride(v.ovrAcOffice),
    acMancave: parseOverride(v.ovrAcMancave),
    pool: parseOverride(v.ovrPool),
    boiler: parseOverride(v.ovrBoiler),
    ev: parseOverride(v.ovrEv)
};

// EV state parsing
const evState = v.evState;
const evPlugged = evState !== EV_STATES.NO_CAR;
const evCharging = evState === EV_STATES.CHARGING;
const evReady = evState === EV_STATES.READY;
const evDone = evState === EV_STATES.FULL;
let evStatusText = evState === EV_STATES.NO_CAR ? 'No car' : 
                   evState === EV_STATES.READY ? 'Ready' : 
                   evState === EV_STATES.FULL ? 'Full' : 
                   evState === EV_STATES.CHARGING ? 'Charging' : `Code ${evState}`;

// Device states
const boilerOn = v.boilerSwitch === 'on';
const boilerForce = v.boilerForce === 'on';
const boilerW = v.boilerPower * (units.boiler || 1);
const boilerFull = boilerW < (config.boiler?.idleThreshold || 50);
const poolW = v.poolPower * (units.poolHeat || 1);
const poolHeating = poolW > (config.pool?.idlePower || 100);
const hrOn = v.heaterRightSwitch === 'on';
const htOn = v.heaterTableSwitch === 'on';
const evOn = v.evSwitch === 'on';
const evW = v.evPower * (units.ev || 1);
const evLimit = v.evLimit;
const acLivingOn = v.acLivingState !== 'off';
const acMancaveOn = v.acMancaveState !== 'off';
const acOfficeOn = v.acOfficeState !== 'off';
const acBedroomOn = v.acBedroomState !== 'off';
const tempLiving = v.tempLiving;
const tempBedroom = v.tempBedroom;
const tempMancave = v.tempMancave;
const coolThreshold = config.summerCoolThreshold || 25;

// Available power = how much we can add before hitting limit
let avail = -p1 + maxImport;
let headroom = avail;

// Plan output
const plan = [];
const gridIcon = isExporting ? '(exp)' : (p1 > maxImport * 0.8 ? '(!)' : '');
const tariffLabel = tariff.toUpperCase().replace('-', ' ');
plan.push(`${tariffLabel} ${gridIcon} | Grid: ${fmtW(p1)} | PV: ${fmtW(pv)} | Avail: ${fmtW(avail)}`);
plan.push(`${isSummer ? 'Summer' : 'Winter'} | EV: ${evStatusText}`);

// Decision object
let decisions = {
    ev: { action: 'none', amps: evLimit },
    boiler: { action: 'none' },
    pool: { action: 'none' },
    heaterRight: { action: 'none' },
    heaterTable: { action: 'none' },
    acLiving: { action: 'none', mode: 'off', temp: 22 },
    acMancave: { action: 'none', mode: 'off', temp: 17 },
    acOffice: { action: 'none', mode: 'off', temp: 22 },
    acBedroom: { action: 'none', mode: 'off', temp: 22 }
};

// === MANUAL OVERRIDES FIRST ===
if (ovr.pool === 'heat' && !poolHeating) {
    decisions.pool.action = 'heat';
    plan.push(`Pool: MANUAL ON`);
} else if (ovr.pool === 'off' && poolHeating) {
    decisions.pool.action = 'off';
    plan.push(`Pool: MANUAL OFF`);
}

if (ovr.boiler === 'heat' && !boilerOn) {
    decisions.boiler.action = 'on';
    plan.push(`Boiler: MANUAL ON`);
} else if (ovr.boiler === 'off' && boilerOn) {
    decisions.boiler.action = 'off';
    plan.push(`Boiler: MANUAL OFF`);
}

if (ovr.ev === 'heat' && evPlugged && !evCharging && !evDone) {
    decisions.ev = { action: 'on', amps: config.ev?.maxAmps || 16 };
    plan.push(`EV: MANUAL CHARGE`);
} else if (ovr.ev === 'off' && evCharging) {
    decisions.ev = { action: 'off', amps: 0 };
    plan.push(`EV: MANUAL OFF`);
}

const acUnits = ['acLiving', 'acBedroom', 'acOffice', 'acMancave'];
const acNames = { acLiving: 'Living', acBedroom: 'Bedroom', acOffice: 'Office', acMancave: 'Mancave' };
const acStates = { acLiving: acLivingOn, acBedroom: acBedroomOn, acOffice: acOfficeOn, acMancave: acMancaveOn };
const acTemps = { acLiving: 22, acBedroom: 22, acOffice: 22, acMancave: 17 };

for (const ac of acUnits) {
    const o = ovr[ac];
    const isOn = acStates[ac];
    const temp = acTemps[ac];
    if (o === 'cool') {
        decisions[ac] = { action: 'cool', mode: 'cool', temp: temp };
        if (!isOn) plan.push(`AC ${acNames[ac]}: MANUAL COOL`);
    } else if (o === 'heat') {
        decisions[ac] = { action: 'heat', mode: 'heat', temp: temp };
        if (!isOn) plan.push(`AC ${acNames[ac]}: MANUAL HEAT`);
    } else if (o === 'off' && isOn) {
        decisions[ac] = { action: 'off', mode: 'off', temp: temp };
        plan.push(`AC ${acNames[ac]}: MANUAL OFF`);
    }
}

if (boilerForce && !boilerFull && ovr.boiler === 'auto') {
    decisions.boiler.action = 'on';
    plan.push(`Boiler: FORCE ON`);
}

// === WINTER LOGIC ===
if (!isSummer) {
    // EV
    if (ovr.ev === 'auto' && decisions.ev.action === 'none') {
        if (evDone) {
            plan.push(`EV: Full`);
        } else if (evPlugged) {
            const wpa = config.ev?.wattsPerAmp || 692;
            const minA = config.ev?.minAmps || 6;
            const maxA = config.ev?.maxAmps || 16;
            const minEvW = minA * wpa;
            let targetA = Math.floor(headroom / wpa);
            targetA = Math.max(minA, Math.min(maxA, targetA));

            if (evCharging) {
                if (headroom < minEvW - hyst && canSwitch('ev', false)) {
                    decisions.ev = { action: 'off', amps: 0 };
                    plan.push(`EV: Pausing (${fmtW(headroom)} < ${fmtW(minEvW)})`);
                } else {
                    // Check if we should adjust amps (with threshold to prevent flapping)
                    const ampDiff = Math.abs(targetA - evLimit);
                    if (ampDiff >= (config.evAmpChangeThreshold || 2)) {
                        decisions.ev = { action: 'adjust', amps: targetA };
                        plan.push(`EV: Adjusting to ${targetA}A`);
                    } else {
                        plan.push(`EV: Charging @ ${evLimit}A`);
                    }
                }
            } else if (evReady) {
                if (tariff === 'peak') {
                    plan.push(`EV: Waiting for off-peak (${tariffInfo.nextTime})`);
                } else if (headroom >= minEvW && canSwitch('ev', true)) {
                    decisions.ev = { action: 'on', amps: targetA };
                    plan.push(`EV: Starting @ ${targetA}A`);
                    headroom -= targetA * wpa;
                } else {
                    plan.push(`EV: Waiting for ${fmtW(minEvW)} (now ${fmtW(headroom)})`);
                }
            }
        }
    }

    // Boiler
    if (ovr.boiler === 'auto' && decisions.boiler.action === 'none') {
        const bw = config.boiler?.power || 2500;
        const time = d.getHours() + d.getMinutes() / 60;
        const deadline = config.boiler?.deadlineWinter || 6.5;
        const urgent = time < deadline && tariff === 'super-off-peak' && !boilerFull;

        if (boilerFull) {
            plan.push(`Boiler: Full`);
        } else if (boilerOn) {
            plan.push(`Boiler: Heating`);
        } else if (urgent) {
            decisions.boiler.action = 'on';
            plan.push(`Boiler: URGENT (deadline ${fmtTime(deadline)})`);
            headroom -= bw;
        } else if (tariff !== 'super-off-peak') {
            plan.push(`Boiler: Waiting for super off-peak (01:00)`);
        } else if (headroom >= bw - hyst && canSwitch('boiler', true)) {
            decisions.boiler.action = 'on';
            plan.push(`Boiler: Starting`);
            headroom -= bw;
        } else {
            plan.push(`Boiler: Waiting for ${fmtW(bw)} (now ${fmtW(headroom)})`);
        }
    }

    // AC Living (heating)
    if (ovr.acLiving === 'auto' && decisions.acLiving.action === 'none') {
        if (acLivingOn) {
            if (tariff === 'peak' && headroom < -hyst && canSwitch('acLiving', false)) {
                decisions.acLiving = { action: 'off', mode: 'off', temp: 21 };
                plan.push(`AC Living: Load shed (peak)`);
            } else {
                plan.push(`AC Living: Heating (${tempLiving.toFixed(1)}C)`);
            }
        } else {
            const pw = config.ac?.living?.power || 1500;
            if (tariff === 'peak') {
                plan.push(`AC Living: Waiting for off-peak (${tariffInfo.nextTime})`);
            } else if (headroom >= pw - hyst && canSwitch('acLiving', true)) {
                decisions.acLiving = { action: 'heat', mode: 'heat', temp: 21 };
                plan.push(`AC Living: Starting`);
                headroom -= pw;
            } else {
                plan.push(`AC Living: Waiting for ${fmtW(pw)} (now ${fmtW(headroom)})`);
            }
        }
    }

    // AC Mancave (heating)
    if (ovr.acMancave === 'auto' && decisions.acMancave.action === 'none') {
        if (acMancaveOn) {
            plan.push(`AC Mancave: Heating (${tempMancave.toFixed(1)}C)`);
        } else {
            const pw = config.ac?.mancave?.power || 1000;
            if (tariff === 'peak') {
                plan.push(`AC Mancave: Waiting for off-peak (${tariffInfo.nextTime})`);
            } else if (headroom >= pw - hyst && canSwitch('acMancave', true)) {
                decisions.acMancave = { action: 'heat', mode: 'heat', temp: 17 };
                plan.push(`AC Mancave: Starting`);
                headroom -= pw;
            }
        }
    }

    // Heater Table
    const htW = config.heaters?.table?.power || 4100;
    if (htOn) {
        if (headroom < -hyst && canSwitch('heaterTable', false)) {
            decisions.heaterTable.action = 'off';
            plan.push(`Heater Table: Turning off (overload)`);
        } else {
            plan.push(`Heater Table: On (${fmtW(htW)})`);
        }
    } else {
        if (tariff === 'peak') {
            plan.push(`Heater Table: Waiting for off-peak (${tariffInfo.nextTime})`);
        } else if (headroom < htW - hyst) {
            plan.push(`Heater Table: Waiting for ${fmtW(htW)} (now ${fmtW(headroom)})`);
        } else if (!canSwitch('heaterTable', true)) {
            plan.push(`Heater Table: Waiting (min time)`);
        } else {
            decisions.heaterTable.action = 'on';
            plan.push(`Heater Table: Starting`);
            headroom -= htW;
        }
    }

    // Heater Right
    const hrW = config.heaters?.right?.power || 2500;
    if (hrOn) {
        if (headroom < -hyst && canSwitch('heaterRight', false)) {
            decisions.heaterRight.action = 'off';
            plan.push(`Heater Right: Turning off (overload)`);
        } else {
            plan.push(`Heater Right: On (${fmtW(hrW)})`);
        }
    } else {
        if (tariff === 'peak') {
            plan.push(`Heater Right: Waiting for off-peak (${tariffInfo.nextTime})`);
        } else if (headroom < hrW - hyst) {
            plan.push(`Heater Right: Waiting for ${fmtW(hrW)} (now ${fmtW(headroom)})`);
        } else if (!canSwitch('heaterRight', true)) {
            plan.push(`Heater Right: Waiting (min time)`);
        } else {
            decisions.heaterRight.action = 'on';
            plan.push(`Heater Right: Starting`);
            headroom -= hrW;
        }
    }

// === SUMMER LOGIC ===
} else {
    // Pool
    if (ovr.pool === 'auto' && decisions.pool.action === 'none') {
        const pw = config.pool?.activePower || 2000;
        if (poolHeating) {
            if (headroom < -hyst && canSwitch('pool', false)) {
                decisions.pool.action = 'off';
                plan.push(`Pool: Pausing`);
            } else {
                plan.push(`Pool: Heating`);
            }
        } else if (headroom >= pw - hyst && canSwitch('pool', true)) {
            decisions.pool.action = 'heat';
            plan.push(`Pool: Starting (low fan)`);
            headroom -= pw;
        } else {
            plan.push(`Pool: Waiting for ${fmtW(pw)} (now ${fmtW(headroom)})`);
        }
    }

    // Boiler
    if (ovr.boiler === 'auto' && decisions.boiler.action === 'none') {
        const bw = config.boiler?.power || 2500;
        if (boilerFull) {
            plan.push(`Boiler: Full`);
        } else if (boilerOn) {
            plan.push(`Boiler: Heating`);
        } else if (headroom >= bw - hyst && canSwitch('boiler', true)) {
            decisions.boiler.action = 'on';
            plan.push(`Boiler: Starting`);
            headroom -= bw;
        } else {
            plan.push(`Boiler: Waiting for ${fmtW(bw)}`);
        }
    }

    // EV
    if (ovr.ev === 'auto' && decisions.ev.action === 'none') {
        if (evDone) {
            plan.push(`EV: Full`);
        } else if (evPlugged) {
            const wpa = config.ev?.wattsPerAmp || 692;
            const minA = config.ev?.minAmps || 6;
            const minEvW = minA * wpa;
            let targetA = Math.floor(headroom / wpa);
            targetA = Math.max(minA, Math.min(config.ev?.maxAmps || 16, targetA));

            if (evCharging) {
                plan.push(`EV: Charging @ ${evLimit}A`);
            } else if (evReady && headroom >= minEvW && tariff !== 'peak' && canSwitch('ev', true)) {
                decisions.ev = { action: 'on', amps: targetA };
                plan.push(`EV: Starting @ ${targetA}A`);
                headroom -= targetA * wpa;
            } else if (tariff === 'peak') {
                plan.push(`EV: Waiting for off-peak`);
            } else {
                plan.push(`EV: Waiting for ${fmtW(minEvW)}`);
            }
        }
    }

    // Cooling (only when exporting)
    if (isExporting) {
        const coolOrder = ['acLiving', 'acBedroom', 'acOffice', 'acMancave'];
        const temps = { acLiving: tempLiving, acBedroom: tempBedroom, acOffice: tempLiving, acMancave: tempMancave };
        const powers = { acLiving: 1500, acBedroom: 1000, acOffice: 1000, acMancave: 1000 };

        for (const ac of coolOrder) {
            if (ovr[ac] !== 'auto') continue;
            if (decisions[ac].action !== 'none') continue;
            const pw = config.ac?.[ac.replace('ac', '').toLowerCase()]?.power || powers[ac];
            const temp = temps[ac];
            const isOn = acStates[ac];

            if (temp > coolThreshold && headroom >= pw) {
                if (!isOn && canSwitch(ac, true)) {
                    decisions[ac] = { action: 'cool', mode: 'cool', temp: 22 };
                    plan.push(`AC ${acNames[ac]}: Cooling (${temp.toFixed(1)}C)`);
                    headroom -= pw;
                } else if (isOn) {
                    plan.push(`AC ${acNames[ac]}: Cooling (${temp.toFixed(1)}C)`);
                }
            } else if (isOn && headroom < -hyst && canSwitch(ac, false)) {
                decisions[ac] = { action: 'off', mode: 'off', temp: 22 };
            }
        }
    } else {
        // Not exporting - turn off cooling
        for (const ac of acUnits) {
            if (ovr[ac] !== 'auto') continue;
            if (acStates[ac] && canSwitch(ac, false)) {
                decisions[ac] = { action: 'off', mode: 'off', temp: 22 };
            }
        }
        plan.push(`Cooling: Waiting for export`);
    }
}

plan.push(`Available: ${fmtW(headroom)}`);

// === BUILD OUTPUTS ===
const outputs = new Array(12).fill(null);
const executed = [];

if (decisions.ev.action === 'on') {
    outputs[0] = { payload: { action: 'turn_on', amps: decisions.ev.amps } };
    updateState('ev', true, { amps: decisions.ev.amps });
    logAction(`EV ON @ ${decisions.ev.amps}A`);
    executed.push(`EV on`);
} else if (decisions.ev.action === 'off') {
    outputs[0] = { payload: { action: 'turn_off' } };
    updateState('ev', false);
    logAction(`EV OFF`);
    executed.push(`EV off`);
} else if (decisions.ev.action === 'adjust') {
    outputs[0] = { payload: { action: 'adjust', amps: decisions.ev.amps } };
    updateState('ev', true, { amps: decisions.ev.amps });
    logAction(`EV ${decisions.ev.amps}A`);
}

if (decisions.boiler.action === 'on' && !boilerOn) {
    outputs[1] = { payload: 'turn_on' };
    updateState('boiler', true);
    logAction(`Boiler ON`);
    executed.push(`Boiler on`);
} else if (decisions.boiler.action === 'off' && boilerOn) {
    outputs[1] = { payload: 'turn_off' };
    updateState('boiler', false);
    logAction(`Boiler OFF`);
    executed.push(`Boiler off`);
}

if (decisions.pool.action === 'heat' && !poolHeating) {
    outputs[2] = { payload: { mode: 'heat', fan: 'low' } };
    updateState('pool', true);
    logAction(`Pool ON`);
    executed.push(`Pool on`);
} else if (decisions.pool.action === 'off' && poolHeating) {
    outputs[2] = { payload: { mode: 'off', fan: 'low' } };
    updateState('pool', false);
    logAction(`Pool OFF`);
    executed.push(`Pool off`);
}

if (decisions.heaterRight.action === 'on' && !hrOn) {
    outputs[3] = { payload: 'turn_on' };
    updateState('heaterRight', true);
    logAction(`Heater R ON`);
    executed.push(`Heater R on`);
} else if (decisions.heaterRight.action === 'off' && hrOn) {
    outputs[3] = { payload: 'turn_off' };
    updateState('heaterRight', false);
    logAction(`Heater R OFF`);
    executed.push(`Heater R off`);
}

if (decisions.heaterTable.action === 'on' && !htOn) {
    outputs[4] = { payload: 'turn_on' };
    updateState('heaterTable', true);
    logAction(`Heater T ON`);
    executed.push(`Heater T on`);
} else if (decisions.heaterTable.action === 'off' && htOn) {
    outputs[4] = { payload: 'turn_off' };
    updateState('heaterTable', false);
    logAction(`Heater T OFF`);
    executed.push(`Heater T off`);
}

if (decisions.acLiving.action !== 'none') {
    outputs[5] = { payload: decisions.acLiving };
    updateState('acLiving', decisions.acLiving.mode !== 'off');
    logAction(`AC Living ${decisions.acLiving.mode}`);
}
if (decisions.acMancave.action !== 'none') {
    outputs[6] = { payload: decisions.acMancave };
    updateState('acMancave', decisions.acMancave.mode !== 'off');
    logAction(`AC Mancave ${decisions.acMancave.mode}`);
}
if (decisions.acOffice.action !== 'none') {
    outputs[7] = { payload: decisions.acOffice };
    updateState('acOffice', decisions.acOffice.mode !== 'off');
    logAction(`AC Office ${decisions.acOffice.mode}`);
}
if (decisions.acBedroom.action !== 'none') {
    outputs[8] = { payload: decisions.acBedroom };
    updateState('acBedroom', decisions.acBedroom.mode !== 'off');
    logAction(`AC Bedroom ${decisions.acBedroom.mode}`);
}

outputs[9] = { payload: { plan, actionLog, tariff, p1, pv, avail, headroom, ovr, isSummer, isExporting } };

const statusLine = `${tariffLabel} | ${fmtW(p1)} | PV ${fmtW(pv)} | ${fmtW(avail)} avail`;
const planText = plan.join(' | ');
const actionsText = actionLog.slice(0,5).join(' | ') || '-';
outputs[10] = { payload: { status: statusLine, plan: planText.substring(0, 250), actions: actionsText.substring(0, 250) } };

if (executed.length > 0 && config.enableNotifications) {
    outputs[11] = { payload: { title: 'Power Manager', message: executed.join(', ') } };
}

// Release mutex
flow.set('isProcessing', false);

node.status({ fill: isExporting ? 'green' : (p1 > maxImport * 0.8 ? 'red' : 'yellow'), shape: 'dot', text: statusLine });
return outputs;

if (!msg.payload) return null;

const config = flow.get('config') || {};
const entities = config.entities?.ev || {
    switch: 'switch.abb_terra_ac_charging',
    limit: 'number.abb_terra_ac_current_limit'
};

const action = msg.payload.action;
const amps = msg.payload.amps || 6;

if (action === 'turn_on' || action === 'adjust') {
    const msgs = [
        { 
            payload: { 
                domain: 'number', 
                service: 'set_value', 
                data: { 
                    entity_id: entities.limit, 
                    value: amps 
                } 
            } 
        }
    ];

    if (action === 'turn_on') {
        msgs.push({ 
            payload: { 
                domain: 'switch', 
                service: 'turn_on', 
                data: { 
                    entity_id: entities.switch 
                } 
            } 
        });
    }

    return [msgs];
} else if (action === 'turn_off') {
    return { 
        payload: { 
            domain: 'switch', 
            service: 'turn_off', 
            data: { 
                entity_id: entities.switch 
            } 
        } 
    };
}

return null;

if (!msg.payload) return null;

const config = flow.get('config') || {};
const entity = config.entities?.pool?.climate || 'climate.98d8639f920c';

return {
    payload: {
        domain: 'climate',
        service: 'set_hvac_mode',
        data: {
            entity_id: entity,
            hvac_mode: msg.payload.mode
        }
    }
};
